const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
let id = 'TK-';
for (let i = 0; i < 8; i++) id += chars[Math.floor(Math.random() * chars.length)];

const input = $('Format Output').item.json;
const action = $('Classify Action').item.json.output || $('Classify Action').item.json;
const isUpgrade = action.upgrade_urgency === true && !action.create_ticket;

// If upgrading, find the existing ticket ID
let ticketId = id;
if (isUpgrade) {
  const tickets = $('Get Open Tickets').all().map(t => t.json);
  const existing = tickets.find(t => t.ticket_id && t.status !== 'closed');
  if (existing) ticketId = existing.ticket_id;
}

return {
  json: {
    ticket_id: ticketId,
    is_upgrade: isUpgrade,
    tenant_name: input.tenant_name,
    phone: input.phone,
    property: input.property,
    unit: input.unit,
    channel: input.channel,
    email: input.email,
    telegram_id: input.telegram_id || '',
    chat_id: input.chat_id || '',
    urgency: action.urgency || 'not_urgent',
    category: action.category || 'general_maintenance',
    summary: action.summary || input.message,
    keyword: action.keyword || '',
    tenant_message: input.message,
    status: action.urgency === 'urgent' ? 'wait_for_approval' : 'open'
  }
};

