// Send "Is your problem resolved?" with Yes/No buttons
const input = $('Format Output').item.json;
const channel = input.channel;
const chat_id = input.chat_id;
const phone = (input.phone || '').replace(/[^0-9]/g, '');
const isFrench = (input.response_text || '').includes('Bonjour') || (input.response_text || '').includes('merci') || (input.response_text || '').includes('votre');

const questionText = isFrench
  ? 'Votre problème est-il résolu?'
  : 'Is your problem resolved?';
const yesText = isFrench ? 'Oui ✅' : 'Yes ✅';
const noText = isFrench ? 'Non ❌' : 'No ❌';

const ticketId = $('Resolve Ticket').item.json.ticket_id || chat_id;

if (channel === 'telegram') {
  await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.telegram.org/bot8460031715:AAE1IQYICVYo3BfDcOjY4IKYVu0iI4V9lZ8/sendMessage',
    body: {
      chat_id: chat_id,
      text: questionText,
      reply_markup: JSON.stringify({
        inline_keyboard: [[
          { text: yesText, callback_data: 'resolve_yes||' + ticketId },
          { text: noText, callback_data: 'resolve_no||' + ticketId }
        ]]
      })
    },
    json: true
  });
} else if (channel === 'whatsapp') {
  await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://graph.facebook.com/v21.0/1002910989571888/messages',
    headers: { 'Content-Type': 'application/json' },
    body: {
      messaging_product: 'whatsapp',
      to: phone,
      type: 'interactive',
      interactive: {
        type: 'button',
        body: { text: questionText },
        action: {
          buttons: [
            { type: 'reply', reply: { id: 'resolve_yes', title: yesText } },
            { type: 'reply', reply: { id: 'resolve_no', title: noText } }
          ]
        }
      }
    },
    json: true
  });
}

return [{ json: { sent: true, ticket_id: ticketId } }];
